async function isEntireEnabled(cwd?: string): Promise<boolean> {
  const { stdout, exitCode } = await runCommandAsync("entire", ["status"], cwd);
  if (exitCode !== 0) {
    return false;
  }

  if (stdout.toLocaleLowerCase().includes("enabled")) {
    return true;
  }

  return false;
}

