	const remotes = remoteOutput
		.split(/\r?\n/)
		.map((entry) => entry.trim())
		.filter((entry) => entry.length > 0);
	if (remotes.length === 0) {
		return null;
	}

	return remotes.includes("origin") ? "origin" : remotes[0];
}

